1	//! R6 — the interactive server's WEB rendering mode of theory content.
2	//!
3	//! The `main/message` and `main/rules` pane BODIES render the SAME blocks the
4	//! batch echo models, but: at width 100 / ribbon 67 (the default HughesPJ
5	//! `Style`, not the batch 110/73); HTML-entity-escaped; with keyword / operator
6	//! / comment tokens wrapped in `<span class="hl_…">`; and WITHOUT the batch
7	//! signature header comment. See workspace/BEHAVIOR.md "Web mode (R6)" for the
8	//! capture provenance of every rule below.
9	//!
10	//! ONE model, TWO render targets. The block-doc builders in `signature` /
11	//! `rule` / `formula` / `lemma` emit their styled glyphs through the [`hl_kw`] /
12	//! [`hl_op_char`] / [`hl_op_text`] / [`hl_comment`] / [`hl_wrap`] wrappers here.
13	//! In batch mode (the default) each wrapper is the identity — the R1–R5 output
14	//! is byte-for-byte unchanged. In web mode (inside [`html_render`]) each wraps
15	//! its glyph in a zero-width span-marker pair — mirroring the sanctioned
16	//! `Annotated.HughesPJ` `AnnotStart`/`AnnotEnd`: `sized_text(0, …)` sentinels
17	//! that flow through best/fits/lay at zero width, so the LAYOUT is identical to
18	//! the plain render. [`html_render`] then renders at (100, 67) and runs one pass
19	//! that entity-escapes the text and expands the sentinels into the spans.
20	
21	use std::cell::Cell;
22	
23	use crate::ast::{AcVariants, Restriction, Rule, Signature};
24	use crate::doc::{beside_op, char, render_with, sized_text, text, Doc};
25	use crate::{formula, lemma, rule, signature};
26	
27	/// Web layout parameters — width 100, ribbon 67 (the default HughesPJ `Style`:
28	/// `lineLength = 100`, `ribbonsPerLine = 1.5`, `round(100/1.5) = 67`). These
29	/// reproduce the SIGNATURE fills byte-for-byte (the fsep continuations reach
30	/// absolute 78 = nest 11 + ribbon 67, and all 82 message-pane signatures render
31	/// byte-identical; see tests/round6_web.rs `signature_pane_sweep`).
32	///
33	/// KNOWN LAYOUT LIMITATION (BEHAVIOR.md "Web mode (R6)" blocker): a single
34	/// (width, ribbon) with this faithful HughesPJ engine does NOT reproduce the
35	/// captured wrap thresholds for the `sep`-based constructs (rule bodies,
36	/// restriction quantifiers) and the pair/AC delimiter drops — a nest-3 rule
37	/// body of content 66 (`c_mult`) wraps in the captures while a nest-3
38	/// bracket-group premise of content 66 (`d_exp`) keeps its `]`, yet this engine
39	/// measures both identically; and the signature fills demand ribbon 67 with
40	/// width ≥ 78 while the rule bodies demand an effective width ~67. The span
41	/// vocabulary, entity escaping, section structure/separators and token content
42	/// are all reproduced; the residual is line-wrapping only. See the blocker note.
43	pub const WEB_WIDTH: isize = 100;
44	pub const WEB_RIBBON: isize = 67;
45	
46	// ── span markers (zero-width sentinels; expanded by `escape_and_expand`) ──────
47	//
48	// Control chars that never occur in theory content (no C0 controls in the
49	// corpus), so they survive the entity-escape pass untouched and are then
50	// expanded into span tags.
51	const M_OPEN: char = '\u{1}'; //  \u{1}<class>\u{2}  ->  <span class="<class>">
52	const M_SEP: char = '\u{2}';
53	const M_CLOSE: char = '\u{3}'; //  \u{3}            ->  </span>
54	
55	thread_local! {
56	    static HL: Cell<bool> = const { Cell::new(false) };
57	}
58	
59	fn hl_on() -> bool {
60	    HL.with(|c| c.get())
61	}
62	
63	/// RAII: enable web-mode styling for the duration of a doc build, restoring the
64	/// previous state on drop (so nesting and panics leave the flag consistent).
65	struct HlGuard(bool);
66	impl HlGuard {
67	    fn on() -> Self {
68	        HlGuard(HL.with(|c| c.replace(true)))
69	    }
70	}
71	impl Drop for HlGuard {
72	    fn drop(&mut self) {
73	        HL.with(|c| c.set(self.0));
74	    }
75	}
76	
77	/// Wrap `d` in a zero-width span-marker pair carrying `class`.
78	fn annot(class: &str, d: Doc) -> Doc {
79	    let open = format!("{M_OPEN}{class}{M_SEP}");
80	    let close = M_CLOSE.to_string();
81	    beside_op(sized_text(0, &open), beside_op(d, sized_text(0, &close)))
82	}
83	
84	// ── glyph wrappers (identity in batch mode) ──────────────────────────────────
85	
86	/// A keyword token (`rule`, `modulo`, `functions:`, …) — `hl_keyword`.
87	pub(crate) fn hl_kw(s: &str) -> Doc {
88	    if hl_on() {
89	        annot("hl_keyword", text(s))
90	    } else {
91	        text(s)
92	    }
93	}
94	
95	/// An operator glyph given as a single char (`=`, `@`, `.`, `(`, `)`, …) —
96	/// `hl_operator`.
97	pub(crate) fn hl_op_char(c: char) -> Doc {
98	    if hl_on() {
99	        annot("hl_operator", char(c))
100	    } else {
101	        char(c)
102	    }
103	}
104	
105	/// An operator glyph given as text (`--[`, `]->`, `-->`, `∀ `, `⇒`, …) —
106	/// `hl_operator`.
107	pub(crate) fn hl_op_text(s: &str) -> Doc {
108	    if hl_on() {
109	        annot("hl_operator", text(s))
110	    } else {
111	        text(s)
112	    }
113	}
114	
115	/// A comment line/block (`// safety formula`, `/* … */`) — `hl_comment`.
116	pub(crate) fn hl_comment(s: &str) -> Doc {
117	    if hl_on() {
118	        annot("hl_comment", text(s))
119	    } else {
120	        text(s)
121	    }
122	}
123	
124	/// Wrap an already-built sub-document in a span of `class` (used for the
125	/// multi-line variants / expanded-formula comment blocks, whose interior keeps
126	/// its own nested keyword/operator spans).
127	pub(crate) fn hl_wrap(class: &str, d: Doc) -> Doc {
128	    if hl_on() {
129	        annot(class, d)
130	    } else {
131	        d
132	    }
133	}
134	
135	// ── the escape + span-expansion pass ─────────────────────────────────────────
136	
137	/// Entity-escape producer text (`& < > " '`, identical to the producers-clean
138	/// `escape_text`) AND expand the zero-width span sentinels into `<span
139	/// class="hl_…">` / `</span>`, in one pass. Leading indent spaces are left raw
140	/// (the producers postprocess turns them into `&nbsp;`); non-ASCII passes raw.
141	fn escape_and_expand(s: &str) -> String {
142	    let mut out = String::with_capacity(s.len() + s.len() / 8 + 16);
143	    let mut it = s.chars();
144	    while let Some(c) = it.next() {
145	        match c {
146	            M_OPEN => {
147	                out.push_str("<span class=\"");
148	                for cc in it.by_ref() {
149	                    if cc == M_SEP {
150	                        break;
151	                    }
152	                    out.push(cc);
153	                }
154	                out.push_str("\">");
155	            }
156	            M_CLOSE => out.push_str("</span>"),
157	            '&' => out.push_str("&amp;"),
158	            '<' => out.push_str("&lt;"),
159	            '>' => out.push_str("&gt;"),
160	            '"' => out.push_str("&quot;"),
161	            '\'' => out.push_str("&#39;"),
162	            _ => out.push(c),
163	        }
164	    }
165	    out
166	}
167	
168	/// Build a styled doc (web mode ON) and render it to an escaped, span-injected
169	/// HTML fragment body at web params. The rendered logical lines carry raw
170	/// leading spaces (postprocessed downstream) and one `\n` per line.
171	fn html_render(build: impl FnOnce() -> Doc) -> String {
172	    let _g = HlGuard::on();
173	    let doc = build();
174	    escape_and_expand(&render_with(WEB_WIDTH, WEB_RIBBON, &doc))
175	}
176	
177	// ── block render entry points ────────────────────────────────────────────────
178	
179	/// The `Signature` message-pane body: `builtins:` / `functions:` / `equations:`
180	/// with NO batch header comment.
181	pub fn render_signature_body(sig: &Signature) -> String {
182	    html_render(|| signature::web_block_doc(sig))
183	}
184	
185	/// One BARE rule (header + body only, no variants comment) — the
186	/// construction/deconstruction message-pane form.
187	pub fn render_rule_bare(r: &Rule) -> String {
188	    html_render(|| rule::core_doc(r))
189	}
190	
191	/// One FULL rule block (header + body + blank + variants comment) — the MSR
192	/// rules-pane form.
193	pub fn render_rule_block(r: &Rule, variants: Option<&AcVariants>) -> String {
194	    html_render(|| rule::block_doc(r, variants))
195	}
196	
197	/// One restriction block (statement, `// safety formula`, expanded-formula
198	/// comment) — the rules-pane restrictions form.
199	pub fn render_restriction(r: &Restriction) -> String {
200	    html_render(|| lemma::restriction_doc(r))
201	}
202	
203	/// One formula in bare (top-level) position at web params — for source views
204	/// and lemma statements (UNVALIDATED: no formula-only web capture; reuses the
205	/// restriction-validated operator spans).
206	pub fn render_formula(f: &crate::ast::Formula) -> String {
207	    html_render(|| formula::doc(f))
208	}
209	
210	// ── section-body assemblers ──────────────────────────────────────────────────
211	
212	/// A `Construction Rules` / `Deconstruction Rules` message-pane body: BARE
213	/// rules joined by one blank line.
214	pub fn render_bare_rules_body(rules: &[Rule]) -> String {
215	    rules
216	        .iter()
217	        .map(render_rule_bare)
218	        .collect::<Vec<_>>()
219	        .join("\n\n")
220	}
221	
222	/// The `Multiset Rewriting Rules` rules-pane body: FULL rule blocks joined by
223	/// TWO blank lines after a `modulo AC` rule and ZERO after a `modulo E` rule
224	/// (corpus: 164 AC→2 / 942 E→0), no trailing.
225	pub fn render_msr_body(rules: &[(Rule, Option<AcVariants>)]) -> String {
226	    let mut out = String::new();
227	    for (i, (r, v)) in rules.iter().enumerate() {
228	        if i > 0 {
229	            let prev = &rules[i - 1].0;
230	            out.push_str(if prev.modulo.as_deref() == Some("AC") {
231	                "\n\n\n"
232	            } else {
233	                "\n"
234	            });
235	        }
236	        out.push_str(&render_rule_block(r, v.as_ref()));
237	    }
238	    out
239	}
240	
241	/// The `Restrictions of the Set of Traces` rules-pane body: restriction blocks
242	/// joined by one blank line.
243	pub fn render_restrictions_body(restrictions: &[Restriction]) -> String {
244	    restrictions
245	        .iter()
246	        .map(render_restriction)
247	        .collect::<Vec<_>>()
248	        .join("\n\n")
249	}
